INSERT INTO guia.dbo.FasesLunares (Nombre,Icono,SignificadoEspiritual,Recomendacion) VALUES
	 (N'Luna Nueva',N'🌑',N'Fase de siembra. La energía está concentrada en el interior, ideal para plantar intenciones.',N'Escribe tus metas de este mes y medita en silencio.'),
	 (N'Luna Creciente',N'🌒',N'Fase de impulso. Las semillas comienzan a brotar. Es tiempo de actuar y nutrir tus proyectos.',N'Toma las primeras acciones concretas para tus planes.'),
	 (N'Cuarto Creciente',N'🌓',N'Fase de desafío. Momento de tomar decisiones y superar los primeros obstáculos.',N'No te rindas ante la presión; fortalece tu voluntad.'),
	 (N'Luna Gibosa',N'🌔',N'Fase de perfeccionamiento. Momento de ajustar detalles antes de la gran culminación.',N'Analiza tus avances y corrige el rumbo si es necesario.'),
	 (N'Luna Llena',N'🌕',N'Fase de plenitud. La luz máxima revela los resultados. Energía de expansión y celebración.',N'Agradece lo logrado y observa lo que sale a la luz.'),
	 (N'Luna Diseminante',N'🌖',N'Fase de compartir. Tiempo de enseñar, comunicar y distribuir los frutos obtenidos.',N'Habla de tus experiencias y ayuda a otros con tu saber.'),
	 (N'Cuarto Menguante',N'🌗',N'Fase de liberación. Momento de soltar lo que ya no sirve y realizar una limpieza interna.',N'Perdona, cierra ciclos y limpia tu espacio físico.'),
	 (N'Luna Balsámica',N'🌘',N'Fase de descanso. El ciclo termina. Tiempo de introspección profunda y recuperación.',N'Duerme más, medita y prepárate para el nuevo inicio.');
